mapper.select:
SELECT * FROM health_risk_warning 
WHERE create_time BETWEEN #{startDate} AND #{endDate}
ORDER BY create_time DESC

mapper.update:
UPDATE health_risk_warning
warning_type = #{warningType}, risk_level = #{riskLevel}, warning_content = #{warningContent}, status = #{status}, handle_status = #{handleStatus}, handle_result = #{handleResult},
WHERE id = #{id}
